namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;
    // Store ratings as list of values per recipe id
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
                Ingredients = ["Baguette", "Tomatoes", "Garlic", "Basil", "Olive oil"],
                Steps = ["Toast bread slices.", "Dice tomatoes and mix with garlic and basil.", "Top bread with tomato mixture and drizzle with olive oil."]
            },
            new Recipe
            {
                Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
                Ingredients = ["Mushrooms", "Cream cheese", "Garlic", "Parmesan", "Breadcrumbs"],
                Steps = ["Remove mushroom stems.", "Mix filling ingredients.", "Stuff caps and bake at 375°F for 20 minutes."]
            },
            new Recipe
            {
                Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
                Ingredients = ["Spaghetti", "Eggs", "Pancetta", "Parmesan", "Black pepper"],
                Steps = ["Cook pasta al dente.", "Fry pancetta until crisp.", "Mix eggs and cheese, toss with hot pasta and pancetta."]
            },
            new Recipe
            {
                Id = 4, Title = "Chicken Tikka Masala", Category = "Main Courses", CategorySlug = "main-courses",
                Ingredients = ["Chicken breast", "Yogurt", "Tomato sauce", "Garam masala", "Cream"],
                Steps = ["Marinate chicken in yogurt and spices.", "Grill chicken pieces.", "Simmer in tomato-cream sauce and serve with rice."]
            },
            new Recipe
            {
                Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
                Steps = ["Melt chocolate and butter.", "Whisk eggs and sugar, fold in chocolate mixture and flour.", "Bake at 425°F for 12 minutes."]
            },
            new Recipe
            {
                Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
                Ingredients = ["Mascarpone", "Espresso", "Ladyfingers", "Cocoa powder", "Eggs"],
                Steps = ["Whisk egg yolks with sugar, fold in mascarpone.", "Dip ladyfingers in espresso.", "Layer cream and ladyfingers, dust with cocoa."]
            },
            new Recipe
            {
                Id = 7, Title = "Mango Smoothie", Category = "Beverages", CategorySlug = "beverages",
                Ingredients = ["Mango", "Yogurt", "Milk", "Honey", "Ice"],
                Steps = ["Combine all ingredients in a blender.", "Blend until smooth.", "Serve immediately."]
            },
            new Recipe
            {
                Id = 8, Title = "Sourdough Bread", Category = "Baking", CategorySlug = "baking",
                Ingredients = ["Bread flour", "Sourdough starter", "Water", "Salt"],
                Steps = ["Mix ingredients and autolyse 30 minutes.", "Stretch and fold every 30 minutes for 2 hours.", "Shape, proof overnight, and bake in Dutch oven at 450°F."]
            },
            new Recipe
            {
                Id = 9, Title = "Vegetable Stir Fry", Category = "Vegetarian", CategorySlug = "vegetarian",
                Ingredients = ["Tofu", "Bell peppers", "Broccoli", "Soy sauce", "Sesame oil"],
                Steps = ["Press and cube tofu.", "Stir-fry vegetables in sesame oil.", "Add tofu and soy sauce, cook until heated through."]
            },
        ];
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<Recipe> GetByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public List<Recipe> GetAll()
    {
        return _recipes.ToList();
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];

        _ratings[recipeId].Add(stars);

        var recipe = GetById(recipeId);
        if (recipe is not null)
        {
            recipe.RatingCount = _ratings[recipeId].Count;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }
}

@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes</PageTitle>

<h1>@(CategorySlug is not null ? GetCategoryName() : "All Recipes")</h1>

@if (!recipes.Any())
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Category</p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<RecipeHub.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = CategorySlug is not null
            ? RecipeService.GetByCategory(CategorySlug)
            : RecipeService.GetAll();
    }

    private string GetCategoryName()
    {
        return recipes.FirstOrDefault()?.Category ?? CategorySlug ?? "Recipes";
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Models
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: <a href="recipes/@recipe.CategorySlug">@recipe.Category</a></p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <h3>Rating</h3>
    <StarRating RecipeId="recipe.Id" AverageRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              style="cursor: pointer; font-size: 1.5rem; color: @(star <= selectedRating ? "gold" : "#ccc");">
            ★
        </span>
    }
    <span class="ms-2 text-muted">
        @if (RatingCount > 0)
        {
            <text>@AverageRating.ToString("0.0") / 5 (@RatingCount ratings)</text>
        }
        else
        {
            <text>No ratings yet</text>
        }
    </span>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-2" role="alert">
        Thank you for rating this recipe!
    </div>
}

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }

        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services
@using RecipeHub.Models
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success" role="alert">
        @successMessage
    </div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="model.Title" />
        <ValidationMessage For="() => model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="model.Category">
            <option value="">-- Select a category --</option>
            <option value="appetizers">Appetizers</option>
            <option value="main-courses">Main Courses</option>
            <option value="desserts">Desserts</option>
            <option value="beverages">Beverages</option>
            <option value="baking">Baking</option>
            <option value="vegetarian">Vegetarian</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.Ingredients" />
        <ValidationMessage For="() => model.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="model.Steps" />
        <ValidationMessage For="() => model.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(model.Title) ||
            string.IsNullOrWhiteSpace(model.Category) ||
            string.IsNullOrWhiteSpace(model.Ingredients) ||
            string.IsNullOrWhiteSpace(model.Steps))
        {
            return;
        }

        var categoryNames = new Dictionary<string, string>
        {
            ["appetizers"] = "Appetizers",
            ["main-courses"] = "Main Courses",
            ["desserts"] = "Desserts",
            ["beverages"] = "Beverages",
            ["baking"] = "Baking",
            ["vegetarian"] = "Vegetarian"
        };

        var recipe = new Recipe
        {
            Title = model.Title,
            CategorySlug = model.Category,
            Category = categoryNames.GetValueOrDefault(model.Category, model.Category),
            Ingredients = model.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = model.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        successMessage = $"Recipe \"{recipe.Title}\" submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        public string Title { get; set; } = string.Empty;
        public string Category { get; set; } = string.Empty;
        public string Ingredients { get; set; } = string.Empty;
        public string Steps { get; set; } = string.Empty;
    }
}

